        MOD = 10**9 + 7

        def digit_sum(x):
            return sum(int(d) for d in str(x))

        def count_good_numbers_up_to(n):
            dp = {}

            def dfs(pos, tight, sum_digits):
                if pos == len(n):
                    return 1 if min_sum <= sum_digits <= max_sum else 0
                if (pos, tight, sum_digits) in dp:
