        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        # Helper function to union two nodes in the union-find structure
        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX != rootY:
